## Marker Extraction

```rust
/// Extract content between markers.
/// Returns the trimmed content between [[ ## name ## ]] and the next [[ ##
fn extract_field(content: &str, field_name: &str) -> Result<String, String> {
    let start_marker = format!("[[ ## {} ## ]]", field_name);
    let end_marker = "[[ ##";

    let start_pos = content.find(&start_marker)
        .ok_or_else(|| format!("marker not found: {}", start_marker))?;

    let after_marker = start_pos + start_marker.len();
    let remaining = &content[after_marker..];

    let end_pos = remaining.find(end_marker)
        .unwrap_or(remaining.len());

    let extracted = remaining[..end_pos].trim();
    Ok(extracted.to_string())
}
```

## Main Parsing Algorithm

```rust
pub fn parse_response_typed<S: Signature>(
    &self,
    response: &Message,
) -> Result<(S::Output, IndexMap<String, FieldMeta>), ParseError> {
    let content = response.content();
    let output_format = S::output_format_content();

    let mut metas = IndexMap::new();
    let mut errors = Vec::new();
    let mut output_map = IndexMap::<String, BamlValue>::new();

    for field in S::output_fields() {
        let rust_name = field.rust_name.to_string();
        let llm_name = field.name;
        let type_ir = (field.type_ir)();

        // 1. Extract raw text
        let raw_text = match extract_field(&content, llm_name) {
            Ok(text) => text,
            Err(_) => {
                errors.push(ParseError::MissingField {
                    field: rust_name.clone(),
                    raw_response: content.to_string(),
                });
                continue;
            }
        };

        // 2. Parse with jsonish
        let parsed: BamlValueWithFlags = match jsonish::from_str(
            output_format,
            &type_ir,
            &raw_text,
            true,  // is_done
        ) {
            Ok(p) => p,
            Err(e) => {
                errors.push(ParseError::CoercionFailed {
                    field: rust_name.clone(),
                    expected_type: type_ir.diagnostic_repr().to_string(),
                    raw_text: raw_text.clone(),
                    source: JsonishError::from(e),
                });
                continue;
            }
        };

        // 3. Collect flags
        let mut flags = Vec::new();
        collect_flags(&parsed, &mut flags);

        // 4. Convert to BamlValue
        let baml_value_with_meta: BamlValueWithMeta<TypeIR> = parsed.clone().into();
        let baml_value: BamlValue = baml_value_with_meta.into();

        // 5. Run constraint checks
        let check_results = run_user_checks(&baml_value, &type_ir);
        let mut checks = Vec::new();

        for result in check_results {
            let passed = result.passed;
            checks.push(ConstraintResult {
                label: result.label.clone(),
                expression: result.expression.clone(),
                passed,
            });

            // Assert failures are errors
            if !passed && is_assert(&type_ir, &result.label) {
                errors.push(ParseError::AssertFailed {
                    field: rust_name.clone(),
                    label: result.label,
                    expression: result.expression,
                    value: baml_value.clone(),
                });
            }
        }

        // 6. Store metadata
        metas.insert(rust_name.clone(), FieldMeta {
            raw_text,
            flags,
            checks,
        });

        // 7. Store parsed value (keyed by LLM name for struct construction)
        output_map.insert(llm_name.to_string(), baml_value);
    }

    // Handle errors
    if !errors.is_empty() {
        let partial = if output_map.is_empty() {
            None
        } else {
            Some(BamlValue::Map(output_map.into_iter().collect()))
        };
        return Err(ParseError::Multiple { errors, partial });
    }

    // Convert map to S::Output
    let output_baml_value = BamlValue::Class(
        "__output".to_string(),  // Class name doesn't matter for conversion
        output_map.into_iter().collect(),
    );

    let typed_output = <S::Output as BamlValueConvert>::try_from_baml_value(
        output_baml_value,
        vec![],
    ).map_err(|e| ParseError::ExtractionFailed {
        field: "<all>".to_string(),
        raw_response: content.to_string(),
        reason: e.to_string(),
    })?;

    Ok((typed_output, metas))
}

fn is_assert(type_ir: &TypeIR, label: &str) -> bool {
    type_ir.constraints.iter().any(|c| 
        c.label == label && c.level == ConstraintLevel::Assert
    )
}
```

