# Task

Define the Predict<S> struct with builder pattern.

## File to Modify
`crates/dspy-rs/src/predictors/predict.rs`

## Struct Definition

```rust
use std::marker::PhantomData;
use std::sync::Arc;
use rig::tool::ToolDyn;

/// Typed predictor for signatures.
pub struct Predict<S: Signature> {
    /// Tools available for function calling
    tools: Vec<Arc<dyn ToolDyn>>,

    /// Demonstration examples
    demos: Vec<S>,

    /// Override for signature instruction
    instruction_override: Option<String>,

    /// PhantomData for type parameter
    _marker: PhantomData<S>,
}

impl<S: Signature> Predict<S> {
    /// Create a new predictor for signature S.
    pub fn new() -> Self {
        Self {
            tools: Vec::new(),
            demos: Vec::new(),
            instruction_override: None,
            _marker: PhantomData,
        }
    }

    /// Create a builder for more configuration.
    pub fn builder() -> PredictBuilder<S> {
        PredictBuilder::new()
    }
}

impl<S: Signature> Default for Predict<S> {
    fn default() -> Self {
        Self::new()
    }
}
```

## Builder Definition

```rust
/// Builder for Predict<S>.
pub struct PredictBuilder<S: Signature> {
    tools: Vec<Arc<dyn ToolDyn>>,
    demos: Vec<S>,
    instruction_override: Option<String>,
    _marker: PhantomData<S>,
}

impl<S: Signature> PredictBuilder<S> {
    fn new() -> Self {
        Self {
            tools: Vec::new(),
            demos: Vec::new(),
            instruction_override: None,
            _marker: PhantomData,
        }
    }

    /// Add a demonstration example.
    pub fn demo(mut self, demo: S) -> Self {
        self.demos.push(demo);
        self
    }

    /// Add multiple demonstrations.
    pub fn with_demos(mut self, demos: impl IntoIterator<Item = S>) -> Self {
        self.demos.extend(demos);
        self
    }

    /// Add a tool for function calling.
    pub fn add_tool(mut self, tool: impl ToolDyn + 'static) -> Self {
        self.tools.push(Arc::new(tool));
        self
    }

    /// Add multiple tools.
    pub fn with_tools(mut self, tools: impl IntoIterator<Item = Arc<dyn ToolDyn>>) -> Self {
        self.tools.extend(tools);
        self
    }

    /// Override the signature instruction.
    pub fn instruction(mut self, instruction: impl Into<String>) -> Self {
        self.instruction_override = Some(instruction.into());
        self
    }

    /// Build the predictor.
    pub fn build(self) -> Predict<S> {
        Predict {
            tools: self.tools,
            demos: self.demos,
            instruction_override: self.instruction_override,
            _marker: PhantomData,
        }
    }
}
```

## Usage Examples

```rust
// Simple
let predict = Predict::<QA>::new();

// With demos
let predict = Predict::<QA>::builder()
    .demo(QA { ... })
    .demo(QA { ... })
    .build();

// With tools
let predict = Predict::<QA>::builder()
    .add_tool(search_tool)
    .add_tool(calculator_tool)
    .build();

// Full configuration
let predict = Predict::<QA>::builder()
    .with_demos(demo_examples)
    .with_tools(available_tools)
    .instruction("Be very precise")
    .build();
```

